responses.response:
Below is a from-scratch JSON Schema validator in plain JavaScript with support for:

- `type`: `string`, `number`, `integer`, `boolean`, `array`, `object`, `null`
- `required`
- `minimum` / `maximum`
- `minLength` / `maxLength`
- `pattern`
- `enum`
- nested objects
- array `items` validation

No external libraries are used.

---

## Implementation

```js
class JSONSchemaValidator {
  validate(schema, data) {
    const errors = [];
    this._validateSchema(schema, data, '', errors);
    return {
      valid: errors.length === 0,
      errors
    };
  }

  _validateSchema(schema, data, path, errors) {
    if (!schema || typeof schema !== 'object') {
      errors.push({
        path,
        message: 'Invalid schema definition'
      });
      return;
    }

    // Type validation
    if (schema.type !== undefined) {
      if (!this._checkType(schema.type, data)) {
        errors.push({
          path,
          message: `Expected type ${schema.type} but got ${this._getType(data)}`
        });
        return; // stop deeper validation if type is wrong
      }
    }

    // Enum validation
    if (schema.enum !== undefined) {
      const found = schema.enum.some(value => this._deepEqual(value, data));
      if (!found) {
        errors.push({
          path,
          message: `Value must be one of: ${JSON.stringify(schema.enum)}`
        });
      }
    }

    // Type-specific validation
    switch (schema.type) {
      case 'number':
      case 'integer':
        this._validateNumber(schema, data, path, errors);
        break;

      case 'string':
        this._validateString(schema, data, path, errors);
        break;

      case 'object':
        this._validateObject(schema, data, path, errors);
        break;

      case 'array':
        this._validateArray(schema, data, path, errors);
        break;
    }
  }

  _validateNumber(schema, data, path, errors) {
    if (schema.minimum !== undefined && data < schema.minimum) {
      errors.push({
        path,
        message: `Value must be >= ${schema.minimum}`
      });
    }

    if (schema.maximum !== undefined && data > schema.maximum) {
      errors.push({
        path,
        message: `Value must be <= ${schema.maximum}`
      });
    }
  }

  _validateString(schema, data, path, errors) {
    if (schema.minLength !== undefined && data.length < schema.minLength) {
      errors.push({
        path,
        message: `String length must be >= ${schema.minLength}`
      });
    }

    if (schema.maxLength !== undefined && data.length > schema.maxLength) {
      errors.push({
        path,
        message: `String length must be <= ${schema.maxLength}`
      });
    }

    if (schema.pattern !== undefined) {
      let regex;
      try {
        regex = new RegExp(schema.pattern);
      } catch (e) {
        errors.push({
          path,
          message: `Invalid regex pattern: ${schema.pattern}`
        });
        return;
      }

      if (!regex.test(data)) {
        errors.push({
          path,
          message: `String does not match pattern: ${schema.pattern}`
        });
      }
    }
  }

  _validateObject(schema, data, path, errors) {
    const properties = schema.properties || {};
    const required = schema.required || [];

    // Required fields
    for (const key of required) {
      if (!(key in data)) {
        errors.push({
          path: this._joinPath(path, key),
          message: 'Required field is missing'
        });
      }
    }

    // Nested properties
    for (const key of Object.keys(properties)) {
      if (key in data) {
        this._validateSchema(
          properties[key],
          data[key],
          this._joinPath(path, key),
          errors
        );
      }
    }
  }

  _validateArray(schema, data, path, errors) {
    if (schema.items !== undefined) {
      for (let i = 0; i < data.length; i++) {
        this._validateSchema(
          schema.items,
          data[i],
          `${path}[${i}]`,
          errors
        );
      }
    }
  }

  _checkType(expectedType, value) {
    switch (expectedType) {
      case 'string':
        return typeof value === 'string';

      case 'number':
        return typeof value === 'number' && Number.isFinite(value);

      case 'integer':
        return typeof value === 'number' && Number.isInteger(value);

      case 'boolean':
        return typeof value === 'boolean';

      case 'array':
        return Array.isArray(value);

      case 'object':
        return value !== null && typeof value === 'object' && !Array.isArray(value);

      case 'null':
        return value === null;

      default:
        return false;
    }
  }

  _getType(value) {
    if (value === null) return 'null';
    if (Array.isArray(value)) return 'array';
    return typeof value;
  }

  _joinPath(base, key) {
    return base ? `${base}.${key}` : key;
  }

  _deepEqual(a, b) {
    if (a === b) return true;

    if (typeof a !== typeof b) return false;

    if (a === null || b === null) return a === b;

    if (Array.isArray(a)) {
      if (!Array.isArray(b) || a.length !== b.length) return false;
      for (let i = 0; i < a.length; i++) {
        if (!this._deepEqual(a[i], b[i])) return false;
      }
      return true;
    }

    if (typeof a === 'object') {
      const aKeys = Object.keys(a);
      const bKeys = Object.keys(b);

      if (aKeys.length !== bKeys.length) return false;

      for (const key of aKeys) {
        if (!Object.prototype.hasOwnProperty.call(b, key)) return false;
        if (!this._deepEqual(a[key], b[key])) return false;
      }

      return true;
    }

    return false;
  }
}
