```typescript
type JsonValue = null | boolean | number | string | JsonValue[] | { [key: string]: JsonValue };

interface ValidationError {
  path: string;
  message: string;
}

interface Schema {
  type?: string | string[];
  required?: string[];
  properties?: { [key: string]: Schema };
  items?: Schema;
  minimum?: number;
  maximum?: number;
  minLength?: number;
  maxLength?: number;
  pattern?: string;
  enum?: JsonValue[];
  additionalProperties?: boolean | Schema;
  [key: string]: any;
}

export class JsonSchemaValidator {
  private errors: ValidationError[] = [];

  validate(data: JsonValue, schema: Schema, path: string = ''): ValidationError[] {
    this.errors = [];
    this._validate(data, schema, path);
    return this.errors;
  }

  private _validate(data: JsonValue, schema: Schema, path: string = ''): void {
    // Type validation
    if (schema.type) {
      this.validateType(data, schema.type, path);
    }

    // Required fields (for objects)
    if (schema.required && typeof data === 'object' && data !== null && !Array.isArray(data)) {
      this.validateRequired(data as Record<string, JsonValue>, schema.required, path);
    }

    // Object validation
    if (typeof data === 'object' && data !== null && !Array.isArray(data)) {
      if (schema.properties) {
        this.validateObject(data as Record<string, JsonValue>, schema, path);
      }
    }

    // Array validation
    if (Array.isArray(data) && schema.items) {
      this.validateArray(data, schema.items, path);
    }

    // Number validations
    if (typeof data === 'number') {
      this.validateNumber(data, schema, path);
    }

    // String validations
    if (typeof data === 'string') {
      this.validateString(data, schema, path);
    }

    // Enum validation
    if (schema.enum) {
      this.validateEnum(data, schema.enum, path);
    }
  }

  private validateType(data: JsonValue, type: string | string[], path: string): void {
    const types = Array.isArray(type) ? type : [type];
    const actualType = this.getType(data);

    if (!types.includes(actualType)) {
      this.addError(path, `Expected type ${types.join(' or ')}, got ${actualType}`);
    }
  }

  private getType(value: JsonValue): string {
    if (value === null) return 'null';
    if (Array.isArray(value)) return 'array';
    return typeof value;
  }

  private validateRequired(data: Record<string, JsonValue>, required: string[], path: string): void {
    for (const field of required) {
      if (!(field in data)) {
        this.addError(path ? `${path}.${field}` : field, `Missing required property: ${field}`);
      }
    }
  }

  private validateObject(data: Record<string, JsonValue>, schema: Schema, path: string): void {
    for (const [key, value] of Object.entries(data)) {
      const propSchema = schema.properties?.[key];
      if (propSchema) {
        const newPath = path ? `${path}.${key}` : key;
        this._validate(value, propSchema, newPath);
      } else if (schema.additionalProperties === false) {
        this.addError(path, `Additional property not allowed: ${key}`);
      } else if (typeof schema.additionalProperties === 'object') {
        const newPath = path ? `${path}.${key}` : key;
        this._validate(value, schema.additionalProperties, newPath);
      }
    }
  }

  private validateArray(data: JsonValue[], itemSchema: Schema, path: string): void {
    data.forEach((item, index) => {
      const newPath = `${path}[${index}]`;
      this._validate(item, itemSchema, newPath);
    });
  }

  private validateNumber(data: number, schema: Schema, path: string): void {
    if (schema.minimum !== undefined && data < schema.minimum) {
      this.addError(path, `Value must be at least ${schema.minimum}`);
    }

    if (schema.maximum !== undefined && data > schema.maximum) {
      this.addError(path, `Value must be at most ${schema.maximum}`);
    }

    if (schema.type === 'integer' && !Number.isInteger(data)) {
      this.addError(path, 'Value must be an integer');
    }
  }

  private validateString(data: string, schema: Schema, path: string): void {
    if (schema.minLength !== undefined && data.length < schema.minLength) {
      this.addError(path, `String must be at least ${schema.minLength} characters`);
    }

    if (schema.maxLength !== undefined && data.length > schema.maxLength) {
      this.addError(path, `String must be at most ${schema.maxLength} characters`);
    }

    if (schema.pattern) {
      try {
        const regex = new RegExp(schema.pattern);
        if (!regex.test(data)) {
          this.addError(path, `String does not match pattern: ${schema.pattern}`);
        }
      } catch (e) {
        this.addError(path, `Invalid regex pattern: ${schema.pattern}`);
      }
    }
  }

  private validateEnum(data: JsonValue, enumValues: JsonValue[], path: string): void {
    const isValid = enumValues.some(enumValue => {
      if (typeof data === 'object' && data !== null && typeof enumValue === 'object' && enumValue !== null) {
        return JSON.stringify(data) === JSON.stringify(enumValue);
      }
      return data === enumValue;
    });

    if (!isValid) {
      this.addError(path, `Value must be one of: ${enumValues.map(v => JSON.stringify(v)).join(', ')}`);
    }
  }

  private addError(path: string, message: string): void {
    this.errors.push({ path, message });
  }

  // Convenience method
  isValid(data: JsonValue, schema: Schema): boolean {
    return this.validate(data, schema).length === 0;
  }

  // Get human readable errors
  getErrorMessage(): string {
    if (this.errors.length === 0) return 'Valid';
    return this.errors.map(err => `${err.path}: ${err.message}`).join('\n');
  }
}
