        if (result !== true) return result;
      }
    }

    // Validate min/max properties
    if (typeof schema.minProperties === 'number' && Object.keys(obj).length < schema.minProperties) {
      return this.fail(`Must have at least ${schema.minProperties} properties but has ${Object.keys(obj).length}`, path);
