        for (let i = 0; i < schema.items.length; i++) {
          if (i >= arr.length) break;
          const result = this.validateAgainstSchema(
            arr[i],
            schema.items[i],
            `${path}[${i}]`
          );
          if (result !== true) return result;
        }

        // additionalItems validation
        if (schema.additionalItems === false && arr.length > schema.items.length) {
          return this.fail(`Array must have at most ${schema.items.length} items`, path);
        } else if (typeof schema.additionalItems === 'object') {
          for (let i = schema.items.length; i < arr.length; i++) {
            const result = this.validateAgainstSchema(
              arr[i],
              schema.additionalItems,
              `${path}[${i}]`
            );
            if (result !== true) return result;
          }
        }
      } else {
        // All items validation
        for (let i = 0; i < arr.length; i++) {
          const result = this.validateAgainstSchema(
            arr[i],
            schema.items,
            `${path}[${i}]`
          );
          if (result !== true) return result;
        }
      }
    }

    // Validate contains (at least one item must match)
    if (schema.contains) {
      let hasValidItem = false;
      for (let i = 0; i < arr.length; i++) {
