    if (typeof schema.minLength === 'number' && str.length < schema.minLength) {
      return this.fail(`String must be at least ${schema.minLength} characters long`, path);
    }
    if (typeof schema.maxLength === 'number' && str.length > schema.maxLength) {
      return this.fail(`String must be at most ${schema.maxLength} characters long`, path);
    }

    // Validate pattern
    if (schema.pattern) {
      const regex = new RegExp(schema.pattern);
      if (!regex.test(str)) {
        return this.fail(`String must match pattern ${schema.pattern}`, path);
      }
    }

    // Validate format (basic implementations only)
    if (schema.format) {
