    // Validate minimum/maximum
    if (typeof schema.minimum === 'number') {
      if (schema.exclusiveMinimum && num <= schema.minimum) {
        return this.fail(`Number must be greater than ${schema.minimum}`, path);
      } else if (!schema.exclusiveMinimum && num < schema.minimum) {
        return this.fail(`Number must be at least ${schema.minimum}`, path);
      }
    }
    if (typeof schema.maximum === 'number') {
      if (schema.exclusiveMaximum && num >= schema.maximum) {
        return this.fail(`Number must be less than ${schema.maximum}`, path);
      } else if (!schema.exclusiveMaximum && num > schema.maximum) {
        return this.fail(`Number must be at most ${schema.maximum}`, path);
      }
    }

