class JsonSchemaValidator {
    constructor() {
        this.errors = [];
    }

    validate(schema, data, path = "") {
        // Reset errors on root call
        if (path === "") this.errors = [];

        if (!schema) return true;

        this._validateType(schema, data, path);
        this._validateEnum(schema, data, path);

        // Type-specific validations
        const type = schema.type;
        if (type === 'number' || type === 'integer') {
            this._validateNumeric(schema, data, path);
        } else if (type === 'string') {
            this._validateString(schema, data, path);
        } else if (type === 'object') {
            this._validateObject(schema, data, path);
        } else if (type === 'array') {
            this._validateArray(schema, data, path);
        }

        return {
            valid: this.errors.length === 0,
            errors: this.errors
        };
    }

    _addError(message, path) {
        this.errors.push({ path: path || "root", message });
    }

    _validateType(schema, data, path) {
        const type = schema.type;
        if (!type) return;

        const actualType = data === null ? 'null' : Array.isArray(data) ? 'array' : typeof data;

        let isValid = false;
        if (type === 'integer') {
            isValid = Number.isInteger(data);
        } else if (type === 'number') {
            isValid = typeof data === 'number';
        } else {
            isValid = actualType === type;
        }

        if (!isValid) {
            this._addError(`Expected type ${type} but got ${actualType}`, path);
        }
    }

    _validateEnum(schema, data, path) {
        if (schema.enum && !schema.enum.includes(data)) {
            this._addError(`Value must be one of: [${schema.enum.join(", ")}]`, path);
        }
    }

    _validateNumeric(schema, data, path) {
        if (typeof data !== 'number') return;
        if (schema.minimum !== undefined && data < schema.minimum) {
            this._addError(`Must be >= ${schema.minimum}`, path);
        }
        if (schema.maximum !== undefined && data > schema.maximum) {
            this._addError(`Must be <= ${schema.maximum}`, path);
        }
    }

    _validateString(schema, data, path) {
        if (typeof data !== 'string') return;
        if (schema.minLength !== undefined && data.length < schema.minLength) {
            this._addError(`Length must be >= ${schema.minLength}`, path);
        }
        if (schema.maxLength !== undefined && data.length > schema.maxLength) {
            this._addError(`Length must be <= ${schema.maxLength}`, path);
        }
        if (schema.pattern) {
            const regex = new RegExp(schema.pattern);
            if (!regex.test(data)) {
                this._addError(`Does not match pattern: ${schema.pattern}`, path);
            }
        }
    }

    _validateObject(schema, data, path) {
        if (typeof data !== 'object' || data === null || Array.isArray(data)) return;

        // Required fields
        if (schema.required) {
            for (const key of schema.required) {
                if (!(key in data)) {
                    this._addError(`Missing required property: ${key}`, path);
                }
            }
        }

        // Properties validation
        if (schema.properties) {
            for (const key in data) {
                if (schema.properties[key]) {
                    this.validate(schema.properties[key], data[key], path ? `${path}.${key}` : key);
                }
            }
        }
    }

    _validateArray(schema, data, path) {
        if (!Array.isArray(data)) return;

        if (schema.items) {
            data.forEach((item, index) => {
                this.validate(schema.items, item, `${path}[${index}]`);
            });
        }
    }
